var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>음… 무슨 말부터….</color>","JPN":"<color=#ffd34c>うーん……何から……</color>","ENG":"<color=#ffd34c>Mm... What should I start with...?</color>","TWN":"<color=#ffd34c>嗯……從哪說起呢……</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>……마브카의… 가장 친한….</color>","JPN":"<color=#ffd34c>……マブカの……大親友……</color>","ENG":"<color=#ffd34c>...It's your best friend–</color>","TWN":"<color=#ffd34c>……瑪卡……最好的……</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>아잇… 내 목소릴 못 알아들을 리…!</color>","JPN":"<color=#ffd34c>もう……私の声がわからないわけ……！</color>","ENG":"<color=#ffd34c>Ugh... I'm sure she'll know whose voice–!</color>","TWN":"<color=#ffd34c>哎呀……不可能聽不出我的聲音……！</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>생일… 축하….</color>","JPN":"<color=#ffd34c>お誕生日……おめで……</color>","ENG":"<color=#ffd34c>Happy... birthday...</color>","TWN":"<color=#ffd34c>生日……快樂……。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하……","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 준 녹음기… 고장이었네….","JPN":"サシャがくれた録音機……壊れてた……","ENG":"The recorder Sasha gave me... it's broken...","TWN":"莎夏給的錄音機……壞掉了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"저기… 마브카.","JPN":"あの……マブカ。","ENG":"Um... Mavka?","TWN":"那個……瑪卡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어떻게 됐어!","JPN":"どうなった！？","ENG":"How did it go?!","TWN":"怎麼樣了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"응… 그, 저기….","JPN":"うん……えっと、あの……","ENG":"Well... Um...","TWN":"嗯……那，那個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"괜찮으면 혹시 나와서 얘기할 수 있을까?","JPN":"よかったら外で話せないかな？","ENG":"Could I talk to you in private?","TWN":"方便出來聊聊嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"여기서 말해. 어차피 사샤도 잠들어 있으니까.","JPN":"ここで話して。どうせサシャも眠っているから。","ENG":"Say it here. Plus, Sasha's fast asleep.","TWN":"就在這裡說吧，反正莎夏也睡著了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그… 저기….","JPN":"その……あの……","ENG":"So... Um...","TWN":"那……那個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"사샤에게 <color=#ffd34c>그림자의 전조</color>가 나타나기 시작했어.","JPN":"サシャに<color=#ffd34c>シャドウの前兆</color>が現れ始めてるの。","ENG":"Sasha's starting to exhibit <color=#ffd34c>prodromal Shadow symptoms</color>.","TWN":"莎夏開始出現<color=#ffd34c>暗影的徵兆</color>了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그림자의 전조…?","JPN":"シャドウの前兆……？","ENG":"Prodromal Shadow symptoms...?","TWN":"暗影的徵兆……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그림자라고? 어떻게…?!","JPN":"シャドウ？　どうして……！？","ENG":"She's becoming a Shadow? But how...?!","TWN":"暗影？怎麼會……？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"크, 큰 소리로 말하면 안 돼. 사샤가 깨면 어쩌려고…","JPN":"お、大声で話しちゃダメ。サシャが目覚めたら……","ENG":"D-don't say it so loud. What if you wake Sasha up...?","TWN":"別，別大聲嚷嚷，要是吵醒了莎夏怎麼辦……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"저기… 아주 잠깐이면 되니까 밖에서 얘기하자, 응?","JPN":"あの……本当に少しでいいから外で話そう、ね？","ENG":"Um... It'll only take a second, so can we please talk outside?","TWN":"那個……只要一下，出去聊聊吧，可以嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……알았어.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"치료할 방법은 있는 거지!","JPN":"治療する方法はあるんでしょう！","ENG":"There is a treatment for it, right?!","TWN":"有治療方法的吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아까는 치료할 수 있다는 것처럼 말했잖아!","JPN":"さっきは治療できるみたいに話してたじゃない！","ENG":"You said that you could treat it!","TWN":"剛才不是說可以治療嗎！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그게….","JPN":"そ、それが……","ENG":"W-well...","TWN":"那，那個……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"단순히 이터니움 부족에 의한 워치의 문제였다면 해결할 수도 있겠지만….","JPN":"単にエタニウム不足によるウォッチの問題だったら解決できたかもしれないけど……","ENG":"If it were simply a matter of her Watch being low on Eternium, it could be easily resolved, but...","TWN":"如果只是因為永恆之金不足導致的能量環問題，還能解決……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"사샤는 좀 달라.","JPN":"サシャはちょっと違うの。","ENG":"Sasha's case is a bit different.","TWN":"可是……莎夏有點不一樣。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"박사님이 자세히 말씀해주시진 않았지만… 사샤가 위험한 상태인건 알아.","JPN":"博士が詳しくは話してくれなかったけど……サシャが危険な状態だってことはわかる。","ENG":"The doctor didn't go into detail, but... I do know that Sasha's in critical condition.","TWN":"博士雖然沒詳細說……但我知道莎夏的情況很危險。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"부, 분명 마브카에게도 숨길만한 이유가 있었을거라 생각해.","JPN":"き、きっとマブカにも隠すだけの理由があったと思うよ。","ENG":"I-I'm sure there was a reason for her to hide it from you, Mavka.","TWN":"我想，她會隱瞞你一定有她的理由。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"우리도 그림자를 치료하는 방법을 연구중이었거든.","JPN":"私たちもシャドウを治療する方法を研究してるから。","ENG":"We're also researching how to treat Shadows.","TWN":"我們也在研究治療暗影的方法。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"확신할 순 없지만, 이 치료법이라면 아마도…!","JPN":"確信はできないけど、この治療方法ならたぶん……！","ENG":"I can't be sure, but maybe the treatment will–!","TWN":"雖然不能確定，但如果用這個治療法的話，或許……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤를 실험체로 삼겠다는 거잖아!","JPN":"サシャを実験体にするってことじゃない！","ENG":"You mean to use Sasha as a test subject!","TWN":"你們是想把莎夏當實驗品吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히익! 그, 그치만 어쩔 수 없잖아…","JPN":"ひいっ！　で、でも仕方ないでしょう……？","ENG":"Eek! But there is nothing else we can do...","TWN":"唔！但，但這是唯一的辦法……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"확실한 건 이대로 가다간, 사샤는 몇 달도 버티지 못해 그림자로 변이될 거야.","JPN":"確かなのは、このままだとサシャは数カ月もしないうちにシャドウに変異するよ。","ENG":"What I do know for sure is that, if Sasha is left untreated, she'll turn into a Shadow within a few months.","TWN":"可以確定的是，照這樣下去，莎夏撐不過幾個月就會變成暗影。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그것만은 막아야 한다고 생각해.","JPN":"それだけは防ぐべきだと思う。","ENG":"And I think that must be prevented no matter what.","TWN":"我覺得必須阻止這件事。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"다, 단순히 빵 한번 줬다고 이러는 게 아냐.","JPN":"た、ただパンをくれたお礼に助けるわけじゃないの。","ENG":"I-I'm not doing this because you gave me some bread.","TWN":"不，不是因為你們給了我一塊麵包，我才這麼說的。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"나도, 드레카도, 너처럼 사람들을 지키기 위해 살아가는 거니까…","JPN":"私も、ドレカも、あなたのように人々を守るために生きてるんだから……","ENG":"Because like you, me, and Dreka, we live to protect the people...","TWN":"我跟德蕾卡和你一樣，都是為了保護人們而活……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"반드시 치료해 줄게! 야, 약속!","JPN":"必ず治療してあげる！　や、約束！","ENG":"I give you my word she'll be treated! I-I promise!","TWN":"我們一定會治好她的！嗯，說定了！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……난 가만히 지켜봐야만 하는 거야?","JPN":"……私は見守るしかできない？","ENG":"...And all I can do is just sit back and watch?","TWN":"……我只能靜靜地看著嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그럴 리가! 친구가 아플 때 곁에 있어주는건 대단한거라고 생각해.","JPN":"そ、そんな！　友だちが苦しんでる時にそばにいてくれるのはすごいことだと思うよ。","ENG":"N-no! I think being there for a friend in need is admirable.","TWN":"那，那怎麼可能！我覺得在朋友生病時，陪在身邊是很棒的事。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"일단 상층부에 전달해놨으니까 지금은 사샤의 곁에 있어 줘.","JPN":"とりあえず上層部には伝えておいたから、今はサシャのそばにいてあげて。","ENG":"I've delivered the news to our higher-ups, so stay with Sasha for now.","TWN":"我已經通知上層了，現在你就在莎夏身邊吧。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사실 너희들을 처음 봤을 때부터 묻고 싶은 게 있었어.","JPN":"実は、あなたたちを初めて見た時から聞きたかったことがある。","ENG":"You know, there was something I wanted to ask you when we first met.","TWN":"其實從第一次見到你們時，我就有個問題想問。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"어, 어? 뭔데?","JPN":"え、えっ？　何？","ENG":"O-oh? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너희들은 왜 북방군에 계속 소속되어 있는거야?","JPN":"あなたたちはどうしてずっと北方軍に所属しているの？","ENG":"Why are you with the Northern Army?","TWN":"你們為什麼一直留在北方軍？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나와 같은 몸을 얻었다는 건… 너희들도 잘 알고 있을 거 아냐.","JPN":"私みたいな体になったということは……あなたたちもよくわかってるんでしょう？","ENG":"With bodies like yours and mine... you know what it implies.","TWN":"擁有和我一樣的身體……表示什麼，你們也很清楚吧。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"응… 맞아.","JPN":"うん……そうだよ。","ENG":"Yeah... I know.","TWN":"嗯……沒錯。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"하지만… 그렇다고 해서 우리가 뭘 할 수 있는데?","JPN":"でも……だからといって私たちに何ができるの？","ENG":"But... What can we do about it?","TWN":"但是……即便如此，我們能做什麼呢？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"반항해서 바뀌는 것이 있을까? 우리의 행동이 사람들의 마음을 움직여줄까?","JPN":"反抗したところで変わるものがあるのかな？　私たちの行動が人々の心を動かせるのかな？","ENG":"Would rebelling against it have changed anything? Would our action capture the heart of the people?","TWN":"反抗會有什麼改變嗎？我們的行動能打動人心嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"난… 솔직히 잘 모르겠어….","JPN":"私は……正直よくわからない……","ENG":"Honestly... I'm not sure...","TWN":"我……說實話不太確定……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"밖에서 했던 말 기억나? 드레카는 나쁜아이가 아니었다는 말.","JPN":"外で話したこと、覚えてる？　ドレカは悪い子じゃなかったってこと。","ENG":"Do you remember what I said? That Dreka wasn't a bad kid?","TWN":"還記得我在外面說的話嗎？德蕾卡不是壞孩子。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"툭하면 울고, 그러다 안아주면 다시 환하게 웃고….","JPN":"すぐ泣いて、それで抱っこしてあげるとまたすごく笑って……","ENG":"She used to cry all the time, then smile when I hugged her...","TWN":"以前她動不動就哭，一抱起來又笑得很燦爛……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"많이 힘들었지만… 이젠 괜찮아.","JPN":"とても辛かったけど……もう大丈夫。","ENG":"It was hard, but... she's all right now.","TWN":"雖然很辛苦……但現在沒事了。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"과정이 어떻게 됐든… 우리가 추구했던 모습이 된 건 맞으니 그걸로 된거 아닐까?","JPN":"どんな過程だったとしても……私たちが求めてきた姿になったのは確かなんだから、それでいいんじゃないかな？","ENG":"Whatever the process may be... We became what we set out to be. Isn't that enough?","TWN":"不管過程如何……我們達到了追求的目標，這樣不就夠了嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분하지도 않은 거야?","JPN":"悔しくないの？","ENG":"Aren't you angry?","TWN":"你難道不覺得憤怒嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"우리가 어떻게 이용당하고 있는지 잘 알잖아!","JPN":"私たちがどうやって利用されてるかちゃんとわかってるでしょう！","ENG":"You know just how we are being used!","TWN":"你知道我們是怎麼被利用的吧！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"부, 분하다고…?","JPN":"く、悔しい……？","ENG":"A-angry...?","TWN":"憤，憤怒……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"불합리하다고 말하고 싶은 거야?","JPN":"不合理だって言いたいわけ？","ENG":"Are you saying that it's unreasonable?","TWN":"你是想說不公平嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"모든 사람들은 각자 불합리한 무언가에 휘둘리고 있는걸?","JPN":"すべての人はそれぞれの不合理な何かに振り回されてるんだよ？","ENG":"But everyone is subject to something unreasonable, don't you think?","TWN":"所有人都在被某種不公平的東西左右，不是嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그렇게 생각하니까 어찌어찌 버틸 수 있었고….","JPN":"そ、そう思ったら何とか耐えられたし……","ENG":"Th-that's how everyone is able to cope with it somehow...","TWN":"這麼想的話，勉強還能撐下去……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"이제 그만 사샤한테 가봐야 하지 않을까…?","JPN":"もうサシャのところに行った方がいいんじゃないかな……？","ENG":"I think you should go back to Sasha now...","TWN":"現在是不是該去找莎夏了……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……무언가 알아낸 게 있다면 바로 말해줘.","JPN":"……何かわかったらすぐ言って。","ENG":"...Let me know if you find out about anything.","TWN":"……如果有任何進展，馬上告訴我。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"응! 약속할게…!","JPN":"うん！　約束する……！","ENG":"Okay. I will...!","TWN":"嗯！我保證……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"……….","JPN":"………","ENG":"...","TWN":"………"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"엇, 여긴 어디지? 난 분명 걔한테 뺨을 때렸다가….","JPN":"えっ、ここはどこ？　私、確かあの子の頬を殴って……","ENG":"Huh? Where am I? I remember slapping her, and–","TWN":"咦，這裡是哪裡？我明明打了那傢伙一巴掌……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앞이 전혀 보이질 않아. 움직일 수도 없고… 가위라도 눌린건가?","JPN":"前が全然見えない。動けないし……金縛りかな？","ENG":"Everything is pitch-black. I can't even move... Is this some kind of sleep paralysis?","TWN":"完全看不見前面，也動不了……是鬼壓床嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"약을 못 먹게 된 이후부터, 조금씩 아파오고 있어.","JPN":"薬が飲めなくなった頃から、少しずつ悪化してる。","ENG":"Ever since I stopped taking my meds, it's been hurting little by little.","TWN":"自從停藥以後，身體慢慢有點痛感。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그런데 이상해. <color=#ff3636>마음은 점점 편안해지는 기분</color>이야.","JPN":"でもおかしい。<color=#ff3636>心はだんだん楽になる気分</color>だな。","ENG":"But it's strange. Because <color=#ff3636>I feel more and more at ease</color>.","TWN":"但是很奇怪。<color=#ff3636>心情卻越來越平靜</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카, 어디있어?","JPN":"マブカ、どこ？","ENG":"Where's Mavka?","TWN":"瑪卡，你在哪裡？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"옆에… 있는거지?","JPN":"そばに……いるんだよね？","ENG":"Is she... next to me?","TWN":"你在旁邊的……對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괜찮을거야... 마브카는 항상 내 곁에 있어줬잖아.","JPN":"大丈夫だよ……マブカはいつも私のそばにいてくれたじゃない。","ENG":"It's going to be all right... Mavka's always been by my side.","TWN":"會沒事的……瑪卡一直都在我身邊呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 분명 잠꼬대하다 또 밀치기라도 한 걸 거야.","JPN":"へへ。きっと寝ぼけてまた押されちゃったのかも。","ENG":"Hehe. I'm sure she pushed me again after talking in her sleep.","TWN":"嘿嘿，肯定是夢遊時又推了我一把。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내 침대를 다 차지하고, 대자로 뻗어 자고 있겠지…?","JPN":"私のベッドを独り占めして、大の字で寝てるはずだよね……","ENG":"She'll take the entire bed with her arms and legs spread out...","TWN":"霸佔我的床，大字形地睡著了吧……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"일어나면… 잔뜩 투정 부려야지.","JPN":"起きたら……いっぱい文句言おう。","ENG":"I should whine about it... when I wake up.","TWN":"等她醒了……我要好好抱怨一番。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그러고보니 수리할 거 잔뜩 밀렸는데…","JPN":"そういえば、修理する物がいっぱいあるのに……","ENG":"Come to think of it, I have a lot of repairs to do...","TWN":"說起來，還有一堆東西要修……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"평소처럼 일과 다 끝내고… 브레멘 동물전대도 보고….","JPN":"いつも通り日課を終えて……ブレーメン動物戦隊も見て……","ENG":"And after finishing work as usual... and watching the Town Soldiers of Bremen...","TWN":"像平時一樣完成所有工作……再看看布萊梅動物戰隊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};